'use client';

import { useEffect, useState, useRef, useCallback } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { v4 as uuidv4 } from 'uuid';
import { getSessionById, getOrganizationById, saveSession, saveTalk } from '@/lib/db';
import type { Session, Organization, Agenda, Talk, Member } from '@/types';

// ---- Web Speech API type declarations ----
interface ISpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  lang: string;
  start(): void;
  stop(): void;
  abort(): void;
  onresult: ((event: ISpeechRecognitionEvent) => void) | null;
  onend: (() => void) | null;
  onerror: ((event: ISpeechRecognitionErrorEvent) => void) | null;
}
interface ISpeechRecognitionEvent extends Event {
  resultIndex: number;
  results: ISpeechRecognitionResultList;
}
interface ISpeechRecognitionResultList {
  readonly length: number;
  [index: number]: ISpeechRecognitionResult;
}
interface ISpeechRecognitionResult {
  readonly isFinal: boolean;
  [index: number]: { readonly transcript: string };
}
interface ISpeechRecognitionErrorEvent extends Event {
  readonly error: string;
}
declare global {
  interface Window {
    SpeechRecognition?: new () => ISpeechRecognition;
    webkitSpeechRecognition?: new () => ISpeechRecognition;
  }
}
// ---- end types ----

const UNKNOWN_SPEAKER_ID = '__unknown__';

function formatElapsed(seconds: number): string {
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  const s = seconds % 60;
  return [h, m, s].map((v) => String(v).padStart(2, '0')).join(':');
}

function formatTime(iso: string): string {
  return new Date(iso).toLocaleTimeString('ja-JP', {
    hour: '2-digit',
    minute: '2-digit',
  });
}

const ROLE_LABEL: Record<string, string> = {
  chair: '議長',
  vice: '副議長',
  exec: '役員',
};

/**
 * Web Speech API の確定テキスト（finalResult）に句読点を後付けする。
 *
 * ルール:
 *  1. 連続空白を1つにまとめる
 *  2. 「でした|ません|ました|です|ます|した」の直後に「。」を挿入
 *     （直後がすでに「。」か「、」の場合はスキップ）
 *     ※ 長いパターンを先に配置し、部分一致（例: ました→した）を防ぐ
 *  3. 「けれど|けど|ので|から|たら|なら|が|は|を|に|と|も|か」の直後に「、」を挿入
 *     （直後がすでに「。」か「、」の場合はスキップ）
 *  4. 「で」の直後に「、」を挿入するが、後続が す/し/は/も/、/。 の場合は除外
 *     （「です」「でした」「では」「でも」の一部を誤分割しないため）
 */
export function addPunctuation(text: string): string {
  // 1. 連続空白を1つにまとめる
  let result = text.replace(/\s+/g, ' ').trim();

  // 2. 句点（。）挿入 — 長いパターンを先に書き部分一致を防ぐ
  result = result.replace(
    /(でした|ません|ました|です|ます|した)(?![。、])/g,
    '$1。\n',
  );

  // 3. 読点（、）挿入 — 長いパターン優先、直後が句読点ならスキップ
  result = result.replace(
    /(けれど|けど|ので|から|たら|なら|が|は|を|に|と|も|か)(?![。、])/g,
    '$1、',
  );
  // 「で」は「です・でした・では・でも」と区別するため後続文字で制限
  result = result.replace(/で(?![すしはも、。])/g, 'で、');

  return result;
}

export default function RecordPage() {
  const params = useParams();
  const router = useRouter();
  const sessionId = params.sessionId as string;

  const [session, setSession] = useState<Session | null>(null);
  const [organization, setOrganization] = useState<Organization | null>(null);
  const [activeAgendaIndex, setActiveAgendaIndex] = useState(0);
  const [selectedSpeakerId, setSelectedSpeakerId] = useState<string>(UNKNOWN_SPEAKER_ID);
  const [isRecording, setIsRecording] = useState(false);
  const [finalText, setFinalText] = useState('');
  const [interimText, setInterimText] = useState('');
  const [elapsedSeconds, setElapsedSeconds] = useState(0);

  const mountTimeRef = useRef(Date.now());
  const recognitionRef = useRef<ISpeechRecognition | null>(null);
  const isRecordingRef = useRef(false);
  const talkScrollRef = useRef<HTMLDivElement>(null);
  const transcriptRef = useRef<HTMLDivElement>(null);
  const lastTalkRef = useRef<Talk | null>(null);
  const lastSaveTimeRef = useRef<number | null>(null);

  // Load data
  useEffect(() => {
    (async () => {
      const s = await getSessionById(sessionId);
      if (!s) {
        console.warn('[RecordPage] session not found:', sessionId);
        return;
      }

      // Defensive null guards — IndexedDB may return undefined fields
      const rawMembers = Array.isArray(s.members) ? s.members : [];
      const rawAgendas = Array.isArray(s.agendas) ? s.agendas : [];

      // Debug: confirm actual data shape
      console.log('[RecordPage] session loaded:', s.id, s.title);
      console.log('[RecordPage] members count:', rawMembers.length,
        '  roles:', rawMembers.map((m) => `${m.lastName}:${m.role}`));
      console.log('[RecordPage] agendas count:', rawAgendas.length,
        '  titles:', rawAgendas.map((a) => a.title));

      const sorted: Session = {
        ...s,
        members: rawMembers,
        agendas: [...rawAgendas].sort((a, b) => a.order - b.order),
      };
      setSession(sorted);

      const org = await getOrganizationById(s.organizationId);
      if (org) setOrganization(org);
    })();
  }, [sessionId]);

  // Elapsed timer
  useEffect(() => {
    const id = setInterval(() => {
      setElapsedSeconds(Math.floor((Date.now() - mountTimeRef.current) / 1000));
    }, 1000);
    return () => clearInterval(id);
  }, []);

  // Auto-scroll talk history when talks change or agenda changes
  useEffect(() => {
    if (talkScrollRef.current) {
      talkScrollRef.current.scrollTop = talkScrollRef.current.scrollHeight;
    }
  }, [session, activeAgendaIndex]);

  // Auto-scroll transcript area
  useEffect(() => {
    if (transcriptRef.current) {
      transcriptRef.current.scrollTop = transcriptRef.current.scrollHeight;
    }
  }, [finalText, interimText]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      isRecordingRef.current = false;
      recognitionRef.current?.abort();
    };
  }, []);

  const startRecognition = useCallback(() => {
    const SpeechRecognitionAPI = window.SpeechRecognition ?? window.webkitSpeechRecognition;
    if (!SpeechRecognitionAPI) {
      alert('このブラウザは音声認識に対応していません。Chrome をお使いください。');
      return;
    }

    const rec = new SpeechRecognitionAPI();
    rec.lang = 'ja-JP';
    rec.continuous = true;
    rec.interimResults = true;

    rec.onresult = (event: ISpeechRecognitionEvent) => {
      let interim = '';
      for (let i = event.resultIndex; i < event.results.length; i++) {
        const result = event.results[i];
        if (result.isFinal) {
          // 確定テキストにのみ句読点を付与（認識中のinterimには適用しない）
          setFinalText((prev) => prev + addPunctuation(result[0].transcript));
        } else {
          interim += result[0].transcript;
        }
      }
      setInterimText(interim);
    };

    rec.onend = () => {
      setInterimText('');
      // Auto-restart while recording is active
      if (isRecordingRef.current) {
        try { rec.start(); } catch { /* ignore */ }
      }
    };

    rec.onerror = (event: ISpeechRecognitionErrorEvent) => {
      if (event.error === 'aborted') return;
      console.error('音声認識エラー:', event.error);
    };

    recognitionRef.current = rec;
    try { rec.start(); } catch { /* ignore */ }
  }, []);

  const stopRecognition = useCallback(() => {
    recognitionRef.current?.abort();
    recognitionRef.current = null;
    setInterimText('');
  }, []);

  const toggleRecording = useCallback(() => {
    if (isRecordingRef.current) {
      isRecordingRef.current = false;
      stopRecognition();
      setIsRecording(false);
    } else {
      isRecordingRef.current = true;
      startRecognition();
      setIsRecording(true);
    }
  }, [startRecognition, stopRecognition]);

  const saveTalkRecord = useCallback(async () => {
    const text = finalText.trim();
    if (!session || !text) return;

    const currentAgenda = session.agendas[activeAgendaIndex];
    if (!currentAgenda) return;

    const now = Date.now();
    const savedAt = new Date().toISOString();
    const MERGE_MS = 3000;

    const shouldMerge =
      lastSaveTimeRef.current !== null &&
      lastTalkRef.current !== null &&
      now - lastSaveTimeRef.current <= MERGE_MS &&
      lastTalkRef.current.speakerId === selectedSpeakerId &&
      lastTalkRef.current.agendaId === currentAgenda.id;

    let updatedSession: Session;

    if (shouldMerge && lastTalkRef.current) {
      const merged: Talk = {
        ...lastTalkRef.current,
        text: lastTalkRef.current.text + '\u3000' + text,
        savedAt,
        isMerged: true,
      };
      await saveTalk(merged);
      lastTalkRef.current = merged;

      updatedSession = {
        ...session,
        agendas: session.agendas.map((a) =>
          a.id === currentAgenda.id
            ? { ...a, talks: a.talks.map((t) => (t.id === merged.id ? merged : t)) }
            : a
        ),
        updatedAt: savedAt,
      };
    } else {
      const newTalk: Talk = {
        id: uuidv4(),
        agendaId: currentAgenda.id,
        speakerId: selectedSpeakerId,
        text,
        savedAt,
        isMerged: false,
      };
      await saveTalk(newTalk);
      lastTalkRef.current = newTalk;

      updatedSession = {
        ...session,
        agendas: session.agendas.map((a) =>
          a.id === currentAgenda.id
            ? { ...a, talks: [...a.talks, newTalk] }
            : a
        ),
        updatedAt: savedAt,
      };
    }

    lastSaveTimeRef.current = now;
    await saveSession(updatedSession);
    setSession(updatedSession);
    setFinalText('');
    setInterimText('');
  }, [session, activeAgendaIndex, selectedSpeakerId, finalText]);

  const goPrev = useCallback(() => {
    setActiveAgendaIndex((i) => Math.max(0, i - 1));
  }, []);

  const goNext = useCallback(() => {
    setActiveAgendaIndex((i) => {
      if (!session) return i;
      return Math.min(session.agendas.length - 1, i + 1);
    });
  }, [session]);

  const endMeeting = useCallback(async () => {
    if (!session) return;
    const updated: Session = {
      ...session,
      status: 'completed',
      updatedAt: new Date().toISOString(),
    };
    await saveSession(updated);
    router.push('/');
  }, [session, router]);

  if (!session) {
    return (
      <div className="flex items-center justify-center bg-[#0f0f0f] text-white/50 text-sm"
        style={{ height: '100dvh' }}>
        読み込み中...
      </div>
    );
  }

  // Null-safe access (type says array, but runtime value may differ)
  const agendas: Agenda[] = Array.isArray(session.agendas) ? session.agendas : [];
  const members: Member[] = Array.isArray(session.members) ? session.members : [];

  const currentAgenda = agendas[activeAgendaIndex];

  const upperMembers = members.filter(
    (m) => m.role === 'chair' || m.role === 'vice' || m.role === 'exec'
  );
  const lowerMembers = members.filter((m) => m.role === 'member');

  const getMember = (id: string): Member | undefined => members.find((m) => m.id === id);

  const isRightBubble = (speakerId: string): boolean => {
    const m = getMember(speakerId);
    return m?.role === 'chair' || m?.role === 'vice';
  };

  // Speaker button renderer
  const SpeakerBtn = ({
    member,
    label,
    roleLabel,
  }: {
    member?: Member;
    label: string;
    roleLabel?: string;
  }) => {
    const id = member?.id ?? UNKNOWN_SPEAKER_ID;
    const active = selectedSpeakerId === id;
    const bg = active ? (member?.avatarColor ?? '#4b5563') : 'transparent';
    return (
      <button
        onClick={() => setSelectedSpeakerId(id)}
        className={`flex-shrink-0 px-3 py-1 rounded text-xs font-medium transition-all border ${
          active ? 'border-transparent text-white' : 'border-white/20 text-white/60 hover:border-white/40 hover:text-white/80'
        }`}
        style={{ backgroundColor: bg }}
      >
        {label}
        {roleLabel && <span className="ml-1 opacity-60 text-[10px]">{roleLabel}</span>}
      </button>
    );
  };

  return (
    <div
      className="flex flex-col text-white overflow-hidden"
      style={{ height: '100dvh', backgroundColor: '#0f0f0f' }}
    >
      {/* ── Header ── */}
      <header className="flex-shrink-0 flex items-center justify-between px-4 py-2 border-b border-white/10 bg-[#1a1a1a]">
        <span className="text-sm font-medium truncate min-w-0 mr-3">
          {organization?.name ?? '—'}{' '}
          <span className="text-white/40">|</span>{' '}
          {session.title}
        </span>
        <div className="flex items-center gap-3 flex-shrink-0">
          <span className="font-mono text-sm text-emerald-400 tabular-nums">
            {formatElapsed(elapsedSeconds)}
          </span>
          <button
            onClick={endMeeting}
            className="px-3 py-1 text-xs rounded bg-red-700 hover:bg-red-600 text-white transition-colors whitespace-nowrap"
          >
            会議を終了
          </button>
        </div>
      </header>

      {/* ── Agenda Tabs ── */}
      <div className="flex-shrink-0 flex items-center gap-2 px-3 py-2 border-b border-white/10 bg-[#161616]">
        <div className="flex gap-1 flex-1 overflow-x-auto pb-0.5 no-scrollbar">
          {agendas.length === 0 && (
            <span className="text-xs text-white/30 px-1">議題が登録されていません</span>
          )}
          {agendas.map((agenda, idx) => (
            <button
              key={agenda.id}
              onClick={() => setActiveAgendaIndex(idx)}
              className={`flex-shrink-0 px-3 py-1 rounded text-xs transition-colors ${
                idx === activeAgendaIndex
                  ? 'bg-blue-600 text-white'
                  : 'bg-white/8 text-white/50 hover:bg-white/15'
              }`}
            >
              {idx + 1}. {agenda.title}
            </button>
          ))}
        </div>
        <button
          onClick={goNext}
          disabled={activeAgendaIndex >= agendas.length - 1}
          className="flex-shrink-0 px-3 py-1 text-xs rounded bg-white/10 hover:bg-white/20 text-white/70 disabled:opacity-25 transition-colors"
        >
          次の議題 →
        </button>
      </div>

      {/* ── Talk History (only scrollable area) ── */}
      <div
        ref={talkScrollRef}
        className="flex-1 overflow-y-auto px-4 py-4 space-y-4 min-h-0"
      >
        {currentAgenda && currentAgenda.talks.length === 0 && (
          <div className="flex items-center justify-center h-full text-white/20 text-sm select-none">
            まだ発言がありません
          </div>
        )}
        {currentAgenda &&
          currentAgenda.talks.map((talk) => {
            const speaker = getMember(talk.speakerId);
            const right = isRightBubble(talk.speakerId);
            const name =
              speaker
                ? speaker.lastName
                : talk.speakerId === UNKNOWN_SPEAKER_ID
                ? '不明'
                : '?';
            const avatarBg = speaker?.avatarColor ?? '#555';
            const time = formatTime(talk.savedAt);

            return (
              <div
                key={talk.id}
                className={`flex flex-col gap-1 ${right ? 'items-end' : 'items-start'}`}
              >
                {/* Speaker info row */}
                <div className={`flex items-center gap-1.5 ${right ? 'flex-row-reverse' : ''}`}>
                  <div
                    className="w-6 h-6 rounded-full flex-shrink-0 flex items-center justify-center text-[11px] font-bold"
                    style={{ backgroundColor: avatarBg }}
                  >
                    {name.charAt(0)}
                  </div>
                  <span className="text-xs text-white/60 font-medium">{name}</span>
                  <span className="text-[10px] text-white/30">{time}</span>
                </div>
                {/* Bubble */}
                <div
                  className={`max-w-[78%] px-3 py-2 text-sm break-words leading-relaxed ${
                    right
                      ? 'bg-blue-600 rounded-2xl rounded-tr-sm text-white'
                      : 'bg-white/12 rounded-2xl rounded-tl-sm text-white/90'
                  }`}
                >
                  {talk.text}
                </div>
              </div>
            );
          })}
      </div>

      {/* ── Speaker Selection Bar ── */}
      <div className="flex-shrink-0 border-t border-white/10 bg-[#161616] px-3 pt-2 pb-2 space-y-1.5">
        {/* Upper: chair / vice / exec */}
        <div className="flex gap-1.5 flex-wrap min-h-[28px] items-center">
          {upperMembers.length === 0 && (
            <span className="text-[10px] text-white/25">議長・副議長・役員なし</span>
          )}
          {upperMembers.map((m) => (
            <SpeakerBtn
              key={m.id}
              member={m}
              label={m.lastName}
              roleLabel={ROLE_LABEL[m.role]}
            />
          ))}
        </div>
        {/* Lower: member + 不明 (horizontal scroll) */}
        <div className="flex gap-1.5 overflow-x-auto pb-0.5 no-scrollbar">
          {lowerMembers.map((m) => (
            <SpeakerBtn key={m.id} member={m} label={m.lastName} />
          ))}
          <SpeakerBtn label="不明" />
        </div>
      </div>

      {/* ── Voice Input Panel ── */}
      <div className="flex-shrink-0 border-t border-white/10 bg-[#1a1a1a] px-3 pt-3 pb-3 flex flex-col gap-2">
        {/* Transcript display */}
        <div
          ref={transcriptRef}
          className="overflow-y-auto rounded-lg border border-white/10 bg-[#0d0d0d] px-3 py-2 text-sm leading-relaxed text-white/85 whitespace-pre-wrap"
          style={{ height: '10lh', minHeight: '8rem' }}
        >
          {finalText || interimText ? (
            <>
              <span>{finalText}</span>
              <span className="text-white/35">{interimText}</span>
            </>
          ) : (
            <span className="text-white/20 select-none">
              ここに音声テキストが表示されます
            </span>
          )}
        </div>

        {/* Record + Save */}
        <div className="flex gap-2">
          <button
            onClick={toggleRecording}
            className={`flex-1 py-2 rounded-lg text-sm font-semibold transition-colors ${
              isRecording
                ? 'bg-amber-600 hover:bg-amber-500 text-white'
                : 'bg-emerald-700 hover:bg-emerald-600 text-white'
            }`}
          >
            {isRecording ? '⏸\u2009一時停止' : '●\u2009録音開始'}
          </button>
          <button
            onClick={saveTalkRecord}
            disabled={!finalText.trim()}
            className="flex-1 py-2 rounded-lg text-sm font-semibold bg-blue-700 hover:bg-blue-600 text-white disabled:opacity-30 transition-colors"
          >
            記録保存
          </button>
        </div>

        {/* Agenda prev / next */}
        <div className="flex gap-2">
          <button
            onClick={goPrev}
            disabled={activeAgendaIndex === 0}
            className="flex-1 py-1.5 rounded text-xs text-white/50 bg-white/5 hover:bg-white/10 disabled:opacity-25 transition-colors"
          >
            ← 前の議題
          </button>
          <button
            onClick={goNext}
            disabled={activeAgendaIndex >= agendas.length - 1}
            className="flex-1 py-1.5 rounded text-xs text-white/50 bg-white/5 hover:bg-white/10 disabled:opacity-25 transition-colors"
          >
            次の議題 →
          </button>
        </div>
      </div>
    </div>
  );
}
